var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님, 저기 보십시오! 구원자님이십니다!","JPN":"隊長、あちらを見てください！　救世主様です！","ENG":"Look, Captain! The Savior is coming!","TWN":"隊長，快看那邊！是救贖者大人！"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"오셨군요. 방금 막 보초들에게 혼자 가셨다는 말을 전해 들은 참이었습니다.","JPN":"戻られたんですね。先ほど見張りから一人でどこかへ向かわれたという話を聞いたところでした。","ENG":"You have arrived. I have just heard from the guards that you went alone.","TWN":"您來了。我剛聽站崗的人說您一個人走了。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 정식으로 보고했다간 다른 분들도 따라오셔야 할 테니까요.","JPN":"はい、正式に報告したら、他の皆さんもついてこないといけなくなりますから。","ENG":"Yes. If I were to make an official report, the others would have to follow.","TWN":"沒錯，因為正式報告的話，各位也都會跟過來吧。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"걱정하게 만들었다면 죄송합니다.","JPN":"心配かけて申し訳ありません。","ENG":"I apologize if I made you worry.","TWN":"抱歉，讓大家擔心了。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"천만에요. 아무 일 없으셔서 다행입니다.","JPN":"いいえ。ご無事で何よりです。","ENG":"No need. I am only glad that you are back, safe and sound.","TWN":"哪裡的話，您沒事就好。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"하지만 위험을 무릅쓰진 말아 주십시오. 구원자님께서는 저희의 희망이시니까요.","JPN":"しかしあまり危険を顧みないことはおやめください。救世主様は我々の希望ですから。","ENG":"Alas, I will have to ask you to be careful next time. You are our only hope.","TWN":"不過請您不要冒險，因為救贖者大人您是我們的希望。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니. 군법에 어긋나는 행동을 저질렀다는 사실 자체가 중요해.","JPN":"いや、今回は軍法に背いたということ自体が問題だ。","ENG":"No, the fact that he disobeyed the rules needs to be discussed.","TWN":"不，做出違反軍法的行為這件事本身也很重要。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌. 기다리고 있었어?","JPN":"アレン、待っていたの？","ENG":"Allen. Were you waiting?","TWN":"艾倫，你是在等我嗎？"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당연하지. 전력의 핵심이 사라졌는데.","JPN":"当たり前だ。最も重要な戦力がどこかにいなくなったんだ。","ENG":"Of course I was. You’re the pillar of our forces.","TWN":"作為戰鬥力核心的人員失蹤了，我當然會如此。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"죄송합니다, 단장님! 저희 대응이 늦어져서 그만……!","JPN":"申し訳ありません団長！　対応が遅くなってしまったせいで……！","ENG":"I'm sorry, Commander! Our response was too late...!","TWN":"對不起，團長！因為我們反應慢了……！"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"책임을 물을 생각은 없다. 원인은 일탈을 벌인 구원자가 제공했으니까.","JPN":"責任を問うつもりはない。原因は逸脱を犯した救世主本人だからな。","ENG":"I'm not here to make anyone else responsible, since it was the Savior who left his post without notice.","TWN":"我不想追究你的責任。相反，這是擅自離隊的救贖者所造成的結果。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"얘기를 나눠야 하는데, 잠시 병사들을 데리고 자리를 비켜 주겠나?","JPN":"少し話し合いがしたいのだが、しばらく兵士たちを連れて、席を外してくれないか？","ENG":"I need a word with him in private. Will all of you excuse us for a moment?","TWN":"我要和他談談，你能帶著士兵先離開嗎？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예, 알겠습니다!","JPN":"はい、かしこまりました！","ENG":"Yes, sir!","TWN":"是，明白！"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"내일이 출정식이다. 설마 잊은 건 아니겠지?","JPN":"明日は出征式だ。まさか忘れたわけではないだろうな？","ENG":"The ceremony of war is going to be held tomorrow. Or did you already forget that?","TWN":"明天是出征儀式。你不會忘了吧？"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"물론이지. 기억하고 있어.","JPN":"もちろん。覚えているよ。","ENG":"Of course not. I remember.","TWN":"我當然記得。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어젯밤엔 루크레시아가 말해 줘서 전하께서 서실 연단도 보러 갔거든. 정말 멋지더라.","JPN":"昨夜はルクレシアが言ってくれて、殿下がお立ちになる演壇も見てきたんだ。すごかったよ。","ENG":"I even went to see the podium that His Highness is going to stand on yesterday. Lucrecia told me about it. It looked great.","TWN":"昨晚露可蕾西亞告訴我了，我還特意去看了殿下要站的講台。很是雄偉。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그리고 가서 전하 얘기만 실컷 했고?","JPN":"それで、そこでルクレシアに殿下の話ばかりして終わったのか？","ENG":"I'm guessing you just talked about His Highness to Lucrecia the whole time.","TWN":"你一直在和露可蕾西亞聊殿下的事？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};